import numpy as np

def build_complete_portfolio_qubo(expected_returns, cov_matrix,
                                   weight_levels, n_select,
                                   risk_aversion=1.0,
                                   budget_penalty=100.0,
                                   cardinality_penalty=100.0):
    """
    Build complete QUBO with risk, return, budget, and cardinality.
    """
    n_assets = len(expected_returns)
    L = len(weight_levels)
    n_vars = n_assets * L

    Q = np.zeros((n_vars, n_vars))

    def var_idx(asset, level):
        return asset * L + level

    # Return objective: maximize sum_i mu_i * w_i
    for i in range(n_assets):
        for l in range(L):
            v = var_idx(i, l)
            Q[v, v] -= expected_returns[i] * weight_levels[l]

    # Risk objective: minimize lambda * sum_{ij} Sigma_ij * w_i * w_j
    for i in range(n_assets):
        for j in range(n_assets):
            for li in range(L):
                for lj in range(L):
                    vi, vj = var_idx(i, li), var_idx(j, lj)
                    Q[vi, vj] += risk_aversion * cov_matrix[i,j] * weight_levels[li] * weight_levels[lj]

    # Budget constraint: (sum w - 1)^2
    for i in range(n_assets):
        for j in range(n_assets):
            for li in range(L):
                for lj in range(L):
                    vi, vj = var_idx(i, li), var_idx(j, lj)
                    Q[vi, vj] += budget_penalty * weight_levels[li] * weight_levels[lj]

    for i in range(n_assets):
        for l in range(L):
            v = var_idx(i, l)
            Q[v, v] -= 2 * budget_penalty * weight_levels[l]

    # One-hot constraint: exactly one level per asset
    one_hot_pen = budget_penalty / 2
    for i in range(n_assets):
        for li in range(L):
            for lj in range(L):
                vi, vj = var_idx(i, li), var_idx(i, lj)
                Q[vi, vj] += one_hot_pen
            Q[var_idx(i, li), var_idx(i, li)] -= 2 * one_hot_pen

    # Cardinality: (sum of indicator[w>0] - n_select)^2
    # indicator[w>0] = sum_{l>0} x_{i,l} for each asset
    for i in range(n_assets):
        for j in range(n_assets):
            for li in range(1, L):  # Skip zero weight
                for lj in range(1, L):
                    vi, vj = var_idx(i, li), var_idx(j, lj)
                    Q[vi, vj] += cardinality_penalty

    for i in range(n_assets):
        for l in range(1, L):
            v = var_idx(i, l)
            Q[v, v] -= 2 * cardinality_penalty * n_select

    def decode(x):
        weights = np.zeros(n_assets)
        for i in range(n_assets):
            for l in range(L):
                if x[var_idx(i, l)] > 0.5:
                    weights[i] = weight_levels[l]
        return weights

    return Q, decode

# Test
mu = np.array([0.12, 0.10, 0.08])
Sigma = np.array([
    [0.04, 0.01, 0.005],
    [0.01, 0.03, 0.008],
    [0.005, 0.008, 0.02]
])
levels = [0.0, 0.33, 0.67, 1.0]

Q, decode = build_complete_portfolio_qubo(mu, Sigma, levels, n_select=2)
print(f'QUBO size: {Q.shape[0]} x {Q.shape[0]}')

best_x, best_e = None, float('inf')
for bits in range(2**Q.shape[0]):
    x = np.array([(bits >> i) & 1 for i in range(Q.shape[0])])
    e = x @ Q @ x
    if e < best_e:
        best_e, best_x = e, x

weights = decode(best_x)
print(f'Optimal weights: {weights.round(2)}')
print(f'Sum: {weights.sum():.2f}')
print(f'Non-zero: {(weights > 0).sum()}')
